from pydantic import BaseModel

class _ToyResult(BaseModel):
    answer: str

class _FakeCompletions:
    def __init__(self, content='{"answer": "ok"}'):
        self.kw = None
        self.content = content
    def create(self, **kw):
        self.kw = kw
        content = self.content
        class _Message:
            pass
        _Message.content = content
        class _Choice:
            message = _Message()
        class _Response:
            choices = [_Choice()]
        return _Response()

class _FakeChat:
    def __init__(self, content='{"answer": "ok"}'):
        self.completions = _FakeCompletions(content)

class _FakeClient:
    def __init__(self, content='{"answer": "ok"}'):
        self.chat = _FakeChat(content)

# Happy path
client = _FakeClient()
result = generate_structured('hello', _ToyResult, schema_name='toy', model='gpt-test', client=client)
assert result == _ToyResult(answer='ok')
assert client.chat.completions.kw['model'] == 'gpt-test'
assert client.chat.completions.kw['messages'] == [{'role': 'user', 'content': 'hello'}]
assert client.chat.completions.kw['response_format']['json_schema']['name'] == 'toy'

# Trailing content after the first JSON object is tolerated.
client = _FakeClient(content='{"answer": "ok"}\n{"junk": 1}')
assert generate_structured('p', _ToyResult, schema_name='toy', client=client) == _ToyResult(answer='ok')
print('ok')

ok

LLM returns [{title, start}, ...]. App-side adds path (sequential) and end (next start or duration).
Pipeline: 1. _build_toc_prompt(segments, meta) — build prompt from xscript segments 2. _call_llm(prompt) — call OpenAI gpt-5.4, return raw [{title, start}] 3. _normalize_sections(raw, duration) — add path/end, sort, dedup, validate 4. Write toc.json to cache dir
toc.json format:
{"sections": [{"path": "1", "title": "Introduction", "start": 0, "end": 750}]}

